const body = $('Webhook').first().json.body;
const convId = (body.conversation_id || '').trim();
const companyId = (body.company_id || '').trim();

const SUPA = 'https://fhkhamwrfwtacwydukvb.supabase.co';
const KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImZoa2hhbXdyZnd0YWN3eWR1a3ZiIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc2NTMyNjcxMywiZXhwIjoyMDgwOTAyNzEzfQ.slNbow0lzBpryTaPPNNPDOV5x_uBqRHQZR38RRk92sY';
const headers = { 'apikey': KEY, 'Authorization': `Bearer ${KEY}`, 'Content-Type': 'application/json' };

const convResp = await this.helpers.httpRequest({ method: 'GET', url: `${SUPA}/rest/v1/conversations?id=eq.${convId}&select=assignee_id,channel_connection_id,contact_name,contact_identifier`, headers });
const conv = convResp[0] || {};

const msgs = await this.helpers.httpRequest({ method: 'GET', url: `${SUPA}/rest/v1/messages?conversation_id=eq.${convId}&order=sent_at.asc&select=direction,sender_type,content,sent_at`, headers });

let sellerPhone = null, sellerName = 'Vendedor';
if (conv.assignee_id) {
  const p = await this.helpers.httpRequest({ method: 'GET', url: `${SUPA}/rest/v1/profiles?id=eq.${conv.assignee_id}&select=name,phone`, headers });
  if (p[0]) {
    sellerName = p[0].name || 'Vendedor';
    let phone = (p[0].phone || '').replace(/\D/g, '');
    if (phone && !phone.startsWith('55')) phone = '55' + phone;
    sellerPhone = phone || null;
  }
}

let instanceName = null;
if (conv.channel_connection_id) {
  const c = await this.helpers.httpRequest({ method: 'GET', url: `${SUPA}/rest/v1/channel_connections?id=eq.${conv.channel_connection_id}&select=external_id,name`, headers });
  if (c[0]) instanceName = c[0].external_id || c[0].name;
}

return [{ json: {
  convId, companyId,
  contactName: conv.contact_name || conv.contact_identifier || 'Cliente',
  sellerPhone, sellerName, instanceName,
  messages: msgs, messageCount: msgs.length,
  hasRequired: !!(sellerPhone && instanceName && msgs.length > 0)
} }];

const data = $json;
const cfg = $('⚙️ Configurações').first().json;

const transcript = data.messages
  .filter(m => m.content?.trim())
  .map(m => {
    const who = m.sender_type === 'lead' ? '👤 Cliente' : m.sender_type === 'agent' ? '👔 Vendedor' : '🤖 Bot';
    return `${who}: ${m.content}`;
  })
  .join('\n');

const userMessage = `Analise esta conversa com ${data.contactName} e gere um resumo para o vendedor ${data.sellerName}.

O resumo deve conter:
- Interesse principal do cliente
- Pontos discutidos
- Receptividade/sentimento do cliente
- Próximos passos sugeridos

Conversa:
---
${transcript}
---

Responda em português, de forma direta e acionável. Máximo 300 palavras.`;

return [{ json: { ...data, transcript, userMessage, systemPrompt: cfg.systemPrompt, model: cfg.model, contextWindowLength: cfg.contextWindowLength } }];

